#include <iostream>
#include <map>
#include <string>
#include <chrono>

#define SESSION_EXPIRY_TIME 3600 // seconds (1 hour)

class Session {
public:
    void create_session(const std::string& session_id) {
        sessions[session_id].data = "";
        sessions[session_id].expires_at = std::chrono::system_clock::now() + std::chrono::seconds(SESSION_EXPIRY_TIME);
        return;
    }

    void access_session(const std::string& session_id) {
        auto it = sessions.find(session_id);
        if (it == sessions.end()) {
            // If the session is expired or non-existent, re-initialize and update the expiry time.
            create_session(session_id);
            return;
        }
        if (std::chrono::system_clock::now() >= it->second.expires_at) {
            invalidate_session(session_id);
            // Re-initialize the session on re-access
            create_session(session_id);
            return;
        }
        return;
    }

    void update_session(const std::string& session_id, const std::string& data) {
        access_session(session_id);
        sessions[session_id].data = data;
    }

    void invalidate_session(const std::string& session_id) {
        // Free the memory allocated for the expired session
        auto it = sessions.find(session_id);
        if (it != sessions.end()) {
            delete[] it->second.data;
        }
        sessions.erase(it);
        return;
    }

private:
    struct Data {
        char* data;
        std::chrono::system_clock::time_point expires_at;
    };
    std::map<std::string, Data> sessions;
};

